<script>
  import {createClient} from '../../plugins/contentful';
  const contentfulClient = createClient();
  export default {
    name: 'team',
    head() {
        return {
            htmlAttrs: {
                xmlns: 'http://www.w3.org/1999/xhtml'
            },
            bodyAttrs: {
                style: 'margin:0;padding:0;-webkit-text-size-adjust:100%;-ms-text-size-adjust:100%;word-wrap: break-word; width: 100%;min-width:100%;'
            }
        }
    },
    asyncData ({ env, params }) {
      return contentfulClient.getEntries({
        'content_type': 'teamMembers',
        'fields.slug': params.slug
      }).then(page => {
        return {
          page: page.items[0]
        }
      }).catch(console.error)
    }
  }
</script>
